#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    long long t;
    if(!(cin>>t)) return 0;
    vector<unsigned long long> results;
    for(long long i=0;i<t;++i){
        unsigned long long n;cin>>n;
        unsigned long long zero_mask = (~n) & (n+1);
        unsigned long long one_mask = n & (~n + 1); // n & -n
        unsigned long long res;
        if(zero_mask==0 || one_mask==0) res=n;
        else res = (n | zero_mask) & (~one_mask);
        results.push_back(res);
    }
    cout<<t<<"\n";
    for(size_t i=0;i<results.size();++i){
        if(i) cout<<"\n";
        cout<<results[i];
    }
    return 0;
}
